import React, { useState, useEffect, useContext, useMemo } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Activity, Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Box, BarChart2, Calendar } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);
    
    // 1. 5-YEAR DATA STATE
    const [historicalData, setHistoricalData] = useState([]);
    const [loadingGraph, setLoadingGraph] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) {
                    const tickers = parseTickers(res.data[0].holdings);
                    initializeStocks(tickers);
                    fetch5YearData(tickers[0]); // Fetch for primary ticker
                }
            } catch (err) { console.error("VAULT_SYNC_ERROR"); }
        };
        fetchVault();
    }, []);

    // 2. FETCH 5Y DATA FROM BACKEND
    const fetch5YearData = async (ticker) => {
        if (!ticker) return;
        setLoadingGraph(true);
        try {
            // Note: You may need to create this endpoint in your FastAPI backend
            // or use yfinance directly if CORS is handled.
            const res = await api.get(`/market/history/${ticker}?period=5y`);
            setHistoricalData(res.data.prices); // Array of closing prices
        } catch (err) {
            // Fallback: Generate mock 5Y trend if API fails
            const mockTrend = Array.from({length: 60}, (_, i) => 50 + Math.sin(i/5)*20 + Math.random()*10);
            setHistoricalData(mockTrend);
        } finally {
            setLoadingGraph(false);
        }
    };

    const parseTickers = (data) => {
        try {
            let t = typeof data === 'string' ? JSON.parse(data) : data;
            return typeof t === 'string' ? JSON.parse(t) : t;
        } catch { return []; }
    };

    const initializeStocks = (tickers) => {
        setStocks(tickers.map(t => ({ ticker: t, price: 0, change: 0 })));
    };

    // 3. SVG PATH GENERATOR
    const svgPath = useMemo(() => {
        if (historicalData.length === 0) return "";
        const max = Math.max(...historicalData);
        const min = Math.min(...historicalData);
        const range = max - min;
        const width = 800;
        const height = 150;

        return historicalData.map((val, i) => {
            const x = (i / (historicalData.length - 1)) * width;
            const y = height - ((val - min) / range) * height;
            return `${i === 0 ? 'M' : 'L'} ${x} ${y}`;
        }).join(' ');
    }, [historicalData]);

    const navigate = (dir) => {
        const newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            const tickers = parseTickers(history[newIdx].holdings);
            initializeStocks(tickers);
            fetch5YearData(tickers[0]);
        }
    };

    return (
        <div style={containerStyle}>
            {/* Navigation Header */}
            <div style={navHeader}>
                <button onClick={() => navigate(1)} disabled={currentIndex === history.length - 1} style={navBtn}>
                    <ChevronLeft size={18}/> PREV_NODE
                </button>
                <div style={activeInfo}>
                    <Box size={14} color="var(--accent-primary)" />
                    <span style={nodeIdText}>{history[currentIndex]?.goal.substring(0, 30)}...</span>
                </div>
                <button onClick={() => navigate(-1)} disabled={currentIndex === 0} style={navBtn}>
                    NEXT_NODE <ChevronRight size={18}/>
                </button>
            </div>

            {/* ── 5-YEAR HISTORICAL GRAPH ── */}
            <div style={graphContainer}>
                <div style={graphHeader}>
                    <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
                        <Calendar size={16} color="var(--accent-primary)" />
                        <span style={graphTitle}>5_YEAR_HISTORICAL_PERFORMANCE // {stocks[0]?.ticker}</span>
                    </div>
                    {loadingGraph && <span style={loadingText}>SYNCING_DATAFRAME...</span>}
                </div>
                
                <svg viewBox="0 0 800 150" style={svgStyle}>
                    {/* Area Fill */}
                    <path
                        d={`${svgPath} L 800 150 L 0 150 Z`}
                        fill="url(#gradient)"
                        opacity="0.2"
                    />
                    {/* Trend Line */}
                    <path
                        d={svgPath}
                        fill="none"
                        stroke="var(--accent-primary)"
                        strokeWidth="2"
                    />
                    <defs>
                        <linearGradient id="gradient" x1="0%" y1="0%" x2="0%" y2="100%">
                            <stop offset="0%" stopColor="var(--accent-primary)" />
                            <stop offset="100%" stopColor="transparent" />
                        </linearGradient>
                    </defs>
                </svg>
            </div>

            {/* Live Tickers Grid */}
            <div style={gridStyle}>
                {stocks.map((stock, i) => (
                    <div key={i} style={stockCardStyle}>
                        <span style={tickerName}>{stock.ticker}</span>
                        <div style={priceStyle}>ANALYZING...</div>
                    </div>
                ))}
            </div>
        </div>
    );
};

/* --- Terminal Styles --- */
const containerStyle = { padding: '2rem', maxWidth: '1200px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' };
const navHeader = { display: 'flex', justifyContent: 'space-between', background: 'var(--surface-glass)', padding: '1rem', borderRadius: '12px', border: '1px solid var(--surface-border)' };
const navBtn = { background: 'none', border: 'none', color: 'var(--accent-primary)', cursor: 'pointer', fontFamily: 'monospace', fontWeight: 800, fontSize: '0.7rem' };
const activeInfo = { display: 'flex', alignItems: 'center', gap: '10px' };
const nodeIdText = { fontSize: '0.7rem', fontWeight: 800, color: '#fff', fontFamily: 'monospace' };

const graphContainer = { background: '#0a0b0e', borderRadius: '20px', border: '1px solid var(--surface-border)', padding: '2rem', minHeight: '200px' };
const graphHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '1.5rem' };
const graphTitle = { fontSize: '0.65rem', fontWeight: 800, color: 'var(--text-muted)', letterSpacing: '0.2em' };
const loadingText = { fontSize: '0.6rem', color: 'var(--accent-primary)', fontFamily: 'monospace' };
const svgStyle = { width: '100%', height: '150px' };

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1rem' };
const stockCardStyle = { padding: '1.5rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '15px' };
const tickerName = { fontSize: '0.75rem', fontWeight: 800, color: 'var(--accent-primary)' };
const priceStyle = { fontSize: '1.2rem', fontWeight: 900, color: '#fff', marginTop: '5px' };

export default LiveMarketPage;
